      "boundary": {
        "in_scope": ["item validation", "stock check", "payment charging", "inventory reservation", "order creation"],
        "out_of_scope": ["cancel order", "track order", "refund payment"]
      },
      "semantic_inputs": [
        {"name": "order_data", "description": "Order data with items, payment_method, shipping_address", "source": "parent input (via ParseAndValidateInput)"}
      ],
      "semantic_outputs": [
        {"name": "order_id", "description": "Generated order ID", "consumer": "parent"},
        {"name": "success", "description": "Boolean indicating success", "consumer": "parent"},
        {"name": "message", "description": "Status message", "consumer": "parent"}
      ],
      "preconditions": ["order_data is valid", "inventory data store is accessible", "payment system is accessible"],
      "postconditions": ["order record created with status 'confirmed'", "inventory decremented for each item", "payment charged"],
