      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "CancelOrder",
      "purpose": "Execute the cancel order workflow: verify order not shipped, refund payment, restore inventory.",
      "behavior": "Check order status is not 'shipped'; refund payment via payment system; restore inventory by incrementing stock; update order status to 'cancelled'.",
      "boundary": {
        "in_scope": ["order status verification", "payment refund", "inventory restoration", "order status update"],
        "out_of_scope": ["place order", "track order", "charge payment"]
      },
      "semantic_inputs": [
        {"name": "order_data", "description": "Order data with order_id", "source": "parent input (via ParseAndValidateInput)"}
      ],
      "semantic_outputs": [
        {"name": "success", "description": "Boolean indicating success", "consumer": "parent"},
        {"name": "order_id", "description": "Order ID being cancelled", "consumer": "parent"},
        {"name": "message", "description": "Status message", "consumer": "parent"}
      ],
      "preconditions": ["order_data contains order_id", "order exists in orders data store", "order status is not 'shipped'"],
      "postconditions": ["order status updated to 'cancelled'", "payment refunded", "inventory restored"],
