      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "TrackOrder",
      "purpose": "Return current order status and estimated delivery.",
      "behavior": "Look up order by order_id in orders data store; retrieve status and estimated delivery date; return them.",
      "boundary": {
        "in_scope": ["order lookup", "status retrieval", "estimated delivery retrieval"],
        "out_of_scope": ["place order", "cancel order", "modify order"]
