    {"from": "parent", "to": "CancelOrder", "data": "parsed_order_data", "note": "if command is cancel"},
    {"from": "parent", "to": "TrackOrder", "data": "parsed_order_data", "note": "if command is track"},
    {"from": "PlaceOrder", "to": "parent", "data": "success, order_id, message", "note": "return result"},
    {"from": "CancelOrder", "to": "parent", "data": "success, order_id, message", "note": "return result"},
    {"from": "TrackOrder", "to": "parent", "data": "status, estimated_delivery, order_id", "note": "return result"}
  ]
